213â†’    private fun moveTrashedPostToDraft(post: PostModel) {
214â†’        /*
215â†’         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
216â†’         * but that'll leave the trashed post in the remote which can be confusing.
217â†’         */
218â†’        if (!checkNetworkConnection.invoke()) {
219â†’            return
